@code {
    [Parameter, EditorRequired] public NotificationPrefs Prefs { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<NotificationPrefs> OnSave { get; set; }

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private HashSet<string> _mutedChannels = [];
    private bool _saving;
    private string? _statusMessage;

    // Known channels the user can mute/unmute
    private readonly List<string> _allChannels = ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _emailNotifications = Prefs.EmailNotifications;
            _pushNotifications = Prefs.PushNotifications;
            _weeklyDigest = Prefs.WeeklyDigest;
            _mutedChannels = [.. Prefs.MutedChannels];
        }
    }

    private void ToggleMute(string channel, bool isMuted)
    {
        if (isMuted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, [.. _mutedChannels]);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Notification preferences saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

