@namespace sv_89a3be97b546484db718470a7badbd0f.Components.Pages.Settings
@using sv_89a3be97b546484db718470a7badbd0f.Services

<section class="settings-section">
    <h4>Profile</h4>
    <p class="text-muted">Manage your personal information</p>

    @if (_statusMessage is not null)
    {
        <div class="alert @(_isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="profile-form">
        <div class="avatar-area mb-4">
            <div class="avatar-preview">
                @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                {
                    <img src="@_avatarUrl" alt="Avatar" />
                }
                else
                {
                    <span class="avatar-placeholder">👤</span>
                }
            </div>
            <div class="avatar-url-display">
                <label class="form-label">Avatar URL</label>
                <input class="form-control form-control-sm" value="@_avatarUrl" readonly />
            </div>
        </div>

        <div class="mb-3">
            <label class="form-label">Display Name</label>
            <input class="form-control" @bind="_displayName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <input type="email" class="form-control" @bind="_email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Bio</label>
            <textarea class="form-control" rows="4" @bind="_bio"></textarea>
        </div>

        <div class="d-flex gap-2">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
                Discard Changes
            </button>
        </div>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public UserProfile Profile { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<UserProfile> OnSave { get; set; }

    private string _displayName = "";
    private string _email = "";
    private string _avatarUrl = "";
    private string _bio = "";
    private bool _saving;
    private string? _statusMessage;
    private bool _isError;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            LoadFromProfile();
        }
    }

    private void LoadFromProfile()
    {
        _displayName = Profile.DisplayName;
        _email = Profile.Email;
        _avatarUrl = Profile.AvatarUrl;
        _bio = Profile.Bio;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Profile saved successfully!";
            _isError = false;
        }
        catch
        {
            _statusMessage = "Failed to save profile. Please try again.";
            _isError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        LoadFromProfile();
        _statusMessage = null;
    }
}

