    <ActiveSessionsTable Sessions="Security.Sessions"
                         CurrentSessionId="@CurrentSessionId"
                         OnRevoke="OnRevoke" />
</section>

@code {
    [Parameter, EditorRequired] public SecuritySettings Security { get; set; } = default!;
    [Parameter] public string CurrentSessionId { get; set; } = "";
    [Parameter, EditorRequired] public EventCallback<(string Current, string New)> OnChangePassword { get; set; }
    [Parameter, EditorRequired] public EventCallback<string> OnRevoke { get; set; }
}

@namespace sv_89a3be97b546484db718470a7badbd0f.Components.Pages.Settings
@using sv_89a3be97b546484db718470a7badbd0f.Services

<section class="settings-section">
    <h4>Appearance</h4>
    <p class="text-muted">Customize how the app looks and feels</p>

    @if (_statusMessage is not null)
    {
        <div class="alert alert-success alert-dismissible fade show" role="alert">
            @_statusMessage
            <button type="button" class="btn-close" @onclick="() => _statusMessage = null"></button>
        </div>
    }

    <div class="row">
        <div class="col-md-6">
            <div class="mb-4">
                <h6>Theme</h6>
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="theme-@theme"
                               value="@theme" checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="theme-@theme">@theme</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Font Size</h6>
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="fs-@size"
                               value="@size" checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="fs-@size">@size</label>
                    </div>
                }
            </div>

            <div class="mb-4">
                <h6>Language</h6>
                <select class="form-select" @bind="_language">
                    <option value="en">English</option>
                    <option value="es">Español</option>
                    <option value="fr">Français</option>
                    <option value="de">Deutsch</option>
                    <option value="ja">日本語</option>
                    <option value="zh">中文</option>
                </select>
            </div>

            <div class="mb-4">
                <h6>Compact Mode</h6>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                    <label class="form-check-label" for="compactMode">
                        Use compact layout
                    </label>
                </div>
            </div>

            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1"></span>
                }
                Save
            </button>
        </div>

        <div class="col-md-6">
            <h6>Preview</h6>
            <div class="preview-area @GetPreviewClasses()">
                <div class="preview-header">
                    <strong>Sample Header</strong>
                </div>
                <div class="preview-body">
                    <p>This is how your content will look with the selected settings.</p>
                    <button class="preview-btn">Sample Button</button>
                </div>
                <div class="preview-footer">
                    <small>Footer text · @GetLanguageName(_language)</small>
                </div>
            </div>
        </div>
    </div>
</section>

@code {
    [Parameter, EditorRequired] public AppearanceSettings Appearance { get; set; } = default!;
    [Parameter, EditorRequired] public EventCallback<AppearanceSettings> OnSave { get; set; }

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _saving;
    private string? _statusMessage;

    protected override void OnParametersSet()
    {
        if (!_saving)
        {
            _theme = Appearance.Theme;
            _fontSize = Appearance.FontSize;
            _language = Appearance.Language;
            _compactMode = Appearance.CompactMode;
        }
    }

    private string GetPreviewClasses()
    {
        var classes = new List<string>();
        classes.Add(_theme.ToLowerInvariant() switch
        {
            "dark" => "preview-dark",
            "system" => "preview-system",
            _ => "preview-light"
        });
        classes.Add($"preview-font-{_fontSize.ToLowerInvariant()}");
        if (_compactMode) classes.Add("preview-compact");
        return string.Join(" ", classes);
    }

    private static string GetLanguageName(string code) => code switch
    {
        "en" => "English",
        "es" => "Español",
        "fr" => "Français",
        "de" => "Deutsch",
        "ja" => "日本語",
        "zh" => "中文",
        _ => code
    };

    private async Task SaveAsync()
    {
        _saving = true;
        _statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await OnSave.InvokeAsync(updated);
            _statusMessage = "Appearance settings saved!";
        }
        finally
        {
            _saving = false;
        }
    }
}

