@page "/settings"
@rendermode InteractiveServer
@namespace sv_89a3be97b546484db718470a7badbd0f.Components.Pages.Settings
@using sv_89a3be97b546484db718470a7badbd0f.Services
@inject ISettingsService SettingsService

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="s => _activeSection = s" />

    <main class="settings-content">
        @if (_loading)
        {
            <div class="d-flex justify-content-center align-items-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (_loadError is not null)
        {
            <div class="alert alert-danger m-4">
                <strong>Error loading settings:</strong> @_loadError
                <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadDataAsync">Retry</button>
            </div>
        }
        else
        {
            @switch (_activeSection)
            {
                case "Profile":
                    <ProfileSection Profile="_profile!" OnSave="SaveProfileAsync" />
                    break;
                case "Notifications":
                    <NotificationsSection Prefs="_notifications!" OnSave="SaveNotificationsAsync" />
                    break;
                case "Security":
                    <SecuritySection Security="_security!"
                                     CurrentSessionId="@_currentSessionId"
                                     OnChangePassword="ChangePasswordAsync"
                                     OnRevoke="RevokeSessionAsync" />
                    break;
                case "Appearance":
                    <AppearanceSection Appearance="_appearance!" OnSave="SaveAppearanceAsync" />
                    break;
            }
        }
    </main>
</div>

@code {
    private string _activeSection = "Profile";
    private bool _loading = true;
    private string? _loadError;

    private UserProfile? _profile;
    private NotificationPrefs? _notifications;
    private SecuritySettings? _security;
    private AppearanceSettings? _appearance;
    private string _currentSessionId = "";

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        _loading = true;
        _loadError = null;
        try
        {
            var profileTask = SettingsService.GetProfileAsync();
            var notifTask = SettingsService.GetNotificationPrefsAsync();
            var securityTask = SettingsService.GetSecuritySettingsAsync();
            var appearanceTask = SettingsService.GetAppearanceAsync();

            await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

            _profile = profileTask.Result;
            _notifications = notifTask.Result;
            _security = securityTask.Result;
            _appearance = appearanceTask.Result;

            // Treat the first session as "current" if available
            if (_security.Sessions.Count > 0)
            {
                _currentSessionId = _security.Sessions[0].Id;
            }
        }
        catch (Exception ex)
        {
            _loadError = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SaveProfileAsync(UserProfile profile)
    {
        await SettingsService.SaveProfileAsync(profile);
        _profile = profile;
    }

    private async Task SaveNotificationsAsync(NotificationPrefs prefs)
    {
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _notifications = prefs;
    }

    private async Task ChangePasswordAsync((string Current, string New) args)
    {
        await SettingsService.ChangePasswordAsync(args.Current, args.New);
        // Refresh security data to update LastPasswordChange
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task RevokeSessionAsync(string sessionId)
    {
        await SettingsService.RevokeSessionAsync(sessionId);
        _security = await SettingsService.GetSecuritySettingsAsync();
    }

    private async Task SaveAppearanceAsync(AppearanceSettings settings)
    {
        await SettingsService.SaveAppearanceAsync(settings);
        _appearance = settings;
    }
}

.settings-layout {
    display: flex;
    min-height: calc(100vh - 56px);
    background: var(--bs-tertiary-bg, #f8f9fa);
}

.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 900px;
}

::deep .settings-section h4 {
    margin-bottom: 0.25rem;
}

::deep .settings-section {
    background: var(--bs-body-bg, #fff);
    border-radius: 0.5rem;
    border: 1px solid var(--bs-border-color, #dee2e6);
    padding: 1.5rem 2rem;
}

